<?php require_once __DIR__.'/includes/functions.php';if($_SERVER['REQUEST_METHOD']==='POST'){check_csrf();$ref=make_ref('FHBF-CON');db()->prepare("INSERT INTO contact_messages(reference,name,email,phone,message,status) VALUES(?,?,?,?,?,'New')")->execute([$ref,$_POST['name'],$_POST['email'],$_POST['phone']??'',$_POST['message']]);flash('success',"Message received. Reference: $ref");redirect('/contact.php');}include __DIR__.'/includes/header.php';?><section class="section"><h1>Contact</h1><form class="card form" method="post"><input type="hidden" name="csrf" value="<?=csrf_token()?>"><label>Name<input name="name" required></label><label>Email<input name="email" required></label><label>Phone<input name="phone"></label><label>Message<textarea name="message" required></textarea></label><button>Send</button></form></section><?php include __DIR__.'/includes/footer.php'; ?>